def sliding_window_max(nums, k):
    if not nums or k == 0:
        return []
    if k >= len(nums):
        return [max(nums)]

    deq = deque()
    result = []
    for i in range(len(nums)):
        if deq and deq[0] == i - k:
            deq.popleft()
        while deq and nums[deq[-1]] < nums[i]:
            deq.pop()
        deq.append(i)
        if i >= k - 1:
            result.append(nums[deq[0]])
    return result

